import type { PieceTexte } from '../pieceTextes';

const texte: PieceTexte = {
  source: 'Sophocle, Antigone — traduction française de Nicolas Artaud, Charpentier, 1859. Source : Wikisource, domaine public.',
  blocs: [
    { k: 'acte', t: 'ANTIGONE' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Ismène, ma sœur, tête chérie , de tous les maux qu’Œdipe a légués à sa race , en sais-tu un dont Jupiter n’ait pas encore affligé notre vie ? En effet, il n’est rien de douloureux, et sans parler de la fatalité qui poursuit notre famille, il n’est point de honte, point d’ignominie que je ne voie dans tes malheurs et dans les miens. Et aujourd’hui, quel est ce nouvel édit que le roi vient de faire proclamer, dit-on, dans toute la ville ? Le connais- tu ? en as-tu entendu parler ? Ne vois-tu pas s’avancer contre ceux qui nous sont chers les outrages de leurs ennemis ?' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Antigone, nulle nouvelle ni agréable ni funeste de nos amis n’est venue jusqu’à moi, depuis que toutes deux nous avons été privées de nos deux frères, mortellement' },
    { k: 'ligne', t: 'frappés l’un par l’autre. L’armée des Argiens ayant pris la fuite cette nuit même, je n’ai rien appris depuis, qui me rende ni plus heureuse, ni plus malheureuse.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Je le savais bien, et je t’ai appelée hors du palais, pour que tu entendes seule ce que j’ai à te dire.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Qu’y a-t-il donc ? car, je le vois, tu agites quelque pensée dans ton esprit.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Eh quoi ! Créon, après avoir accordé à l’un de nos frères les honneurs de la sépulture, n’en a-t-il pas indignement privé l’autre ? Il a, dit-on, enseveli Étéocle dans la terre, ainsi qu’il était juste, et conformément aux lois, et lui a assuré une place honorable aux enfers parmi les morts : mais l’infortuné Polynice, il défend aux citoyens d’enfermer son cadavre dans une tombe et de le pleurer ; il veut qu’il reste privé de regrets, privé de sépulture, en proie aux oiseaux dévorants, qui en feront leur pâture. Tels sont les ordres que la bonté de Créon te signifie ainsi qu’à moi, oui, à moi-même ; et lui-même viendra, dit-on, en ces lieux, les proclamer à ceux qui les ignorent ; et ce n’est pas pour lui chose de peu d’importance, mais il menace quiconque les violera, d’être lapidé par le peuple. Te voilà informée des faits ; bientôt tu montreras si tu as de nobles sentiments, ou si tu démens ta naissance.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Mais, malheureuse, si les choses en sont là, que' },
    { k: 'ligne', t: 'puis-je gagner, soit à concilier, soit à prendre parti ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Vois si tu es prête à m’aider et à seconder mes efforts.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Quelle est donc ta pensée ? qu’oses-tu tenter ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Vois si, avec ta sœur, tu veux enlever le cadavre ?' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Songes-tu donc à l’ensevelir, malgré la défense publique ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Oui, j’ensevelirai mon frère, qui est aussi le tien, que tu le veuilles ou non ; jamais on ne m’accusera d’avoir trahi mon devoir.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Quoi, malheureuse, malgré la défense de Créon ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Mais il n’a pas le droit de m’interdire l’approche des miens.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Hélas ! ma sœur, songe que notre malheureux père est mort dans l’exécration et l’opprobre, et qu’après avoir lui-même découvert ses crimes, il se perça les yeux de ses propres mains ; puis celle qu’une double calamité fit sa mère et son épouse mit fin à sa vie par un lacet fatal ; enfin nos deux frères, les infortunés, le même jour, se sont mutuellement donné la mort, percés par la main l’un de l’autre. Et nous deux, maintenant restées seules, considère combien notre fin sera bien plus misérable, si, au mépris de la loi, nous bravons les ordres et l’autorité de nos maîtres ! D’ailleurs, il faut songer d’abord que nous sommes de faibles femmes, incapables de lutter' },
    { k: 'ligne', t: 'contre les hommes, et ensuite, puisque nous dépendons de plus puissants que nous, nous sommes destinées à subir ces lois, et de plus dures encore. Pour moi donc, priant les mânes de me pardonner si je cède à la violence, j’obéirai à ceux qui possèdent le pouvoir ; car vouloir faire ce qui passe nos forces, c’est de la démence.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Je ne veux point te contraindre ; et si, même à présent, tu voulais partager mes soins, je n’accepterais pas volontiers ton secours. Agis comme il te convient, moi je l’ensevelirai ; il me sera beau de mourir en remplissant ce devoir. Je reposerai, saintement criminelle, auprès d’un frère chéri ; car j’ai à plaire aux dieux des enfers plus longtemps qu’aux hommes sur cette terre. Là, en effet, mon séjour doit être éternel. Toi, si tel est ton sentiment, méprise les ordres respectables des dieux.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Je ne les méprise point, mais je n’ai pas la force de lutter contre la volonté d’une ville entière.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Couvre-toi de ce prétexte ; pour moi, je vais élever une tombe au frère le plus chéri.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Hélas ! infortunée, combien je tremble pour toi !' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Ne crains pas pour moi ; songe plutôt à ta sûreté.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Au moins ne révèle ce dessein à personne ; mais tiens-le secret, j’en ferai de même.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Tu montres une ardeur bouillante, où il faut du sang-froid.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Je sais, du moins, que je plais à ceux qu’il m’importe de satisfaire.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Si toutefois tu peux réussir ; mais tu entreprends l’impossible.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Eh bien ! quand la force me manquera, je m’arrêterai.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Mais il faut commencer par ne pas poursuivre l’impossible.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Si tu parles ainsi , tu mériteras ma haine , et tu seras justement odieuse à l’ombre d’un frère. Mais abandonne-moi au sort terrible dont ma témérité me menace. Car je ne subirai pas de supplice si affreux, qu’il me prive d’une mort glorieuse.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Eh bien ! va donc, si telle est ton envie ; sache-le cependant, tu es imprudente, mais tu es vraiment dévouée à tes amis.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: '{Strophe 1.) Soleil radieux, la plus belle des lumières qui ait jamais lui sur Thèbes aux sept portes, œil éclatant' },
    { k: 'ligne', t: 'du jour, tu as enfin brillé sur les eaux de Dircé, tu as fait fuir d’une fuite précipitée le mortel au bouclier blanc, parti d’Argos armé de toutes pièces ; lui qui, suscité contre notre patrie par la querelle indécise de Polynice, a fondu sur notre contrée, en poussant des cris aigus, tel que l’aigle couvert de ses ailes blanches comme la neige, entraînant de nombreux guerriers armés de casques à la crinière ondoyante.' },
    { k: 'ligne', t: '{Antistrophe 1.) Il dominait sur nos murs, il enveloppait d’un cercle de lances altérées de carnage l’ouverture de nos sept portes ; mais il a fui, avant d’avoir assouvi sa fureur dans notre sang, et avant que le feu des torches de sapin n’eût atteint les tours qui couronnent notre ville, tant fut terrible le tumulte guerrier qui éclata derrière lui, attaque à laquelle ne put résister le dragon ennemi ! Car Jupiter déteste la jactance d’une langue présomptueuse ; et, les voyant s’élancer comme un torrent, dédaignant le fracas de leurs armures d’or, des éclats de sa foudre il renverse le guerrier, qui déjà sur le sommet des remparts se préparait à pousser le cri de victoire.' },
    { k: 'ligne', t: '{Strophe 2.) Il tombe précipité sur la terre retentissante, le guerrier qui portait la flamme, et qui tout à l’heure, ivre de fureur, ne respirant que la haine, exhalait contre Thèbes le souffle ardent de sa colère. Sur' },
    { k: 'ligne', t: 'd’autres, le redoutable Mars, semant la terreur parmi nos ennemis, exerce d’autres vengeances. Sept chefs postés devant les sept portes, et opposés à autant d’adversaires, abandonnèrent le trophée de leurs armes d’airain à Jupiter triomphateur : excepté les deux infortunés, issus du même père et de la même mère, qui, dirigeant l’un contre l’autre leurs lances réciproquement victorieuses, se donnèrent une mort mutuelle.' },
    { k: 'ligne', t: '{Antistrophe 2.) Mais la victoire au glorieux renom est venue rendre l’allégresse à Thèbes, célèbre par ses chars. Après les combats, oubliez maintenant les dangers, et entrons dans tous les temples des dieux, pour que la nuit entière se passe à des danses animées ; que Bacchus, qui livre Thèbes à la joie, préside à nos jeux.' },
    { k: 'ligne', t: 'Mais je vois s’avancer le nouveau roi de cette contrée, Créon, fils de Ménécée, que les événements envoyés par les dieux nous ont donné ; quel projet occupe sa pensée, pour qu’il ait convoqué par une proclamation publique cette assemblée de vieillards ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Citoyens, les dieux, après avoir déchaîné de longs orages sur notre patrie, lui ont enfin rendu le calme et la sécurité. Je vous ai, par mes messagers, convoqués entre tous, parce que je sais que vous avez de tout temps appuyé le trône de Laïos, puis celui d’Œdipe, lorsqu’il eut relevé l’État chancelant, et après sa mort, vous êtes restés constamment fidèles à ses fils. Et depuis que ceux-ci, par un destin commun, périrent en un même jour, mutuellement frappés de leur main fratricide, je possède l’autorité et le trône, en vertu de ma proche parenté avec ceux qui sont morts. Il est impossible de connaître l’âme,' },
    { k: 'ligne', t: 'le caractère et la pensée d’un homme, avant de l’avoir vu longtemps exercer le pouvoir et appliquer les lois. Quant à moi, celui qui, chargé d’un État, ne suit pas les conseils les plus sages, mais qui ferme les bouches par la crainte, m’a paru de tout temps le plus pervers des hommes ; et celui qui préfère un ami aux intérêts de sa patrie, je le méprise. Pour moi, j’en atteste Jupiter, qui voit tout, je ne saurais garder le silence, en voyant un malheur menacer le salut de mes concitoyens, ni regarder jamais, comme un ami tout homme hostile à ma patrie : je sais trop que d’elle seule dépend notre salut, et que, si nous la gouvernons bien, nous aurons assez d’amis. C’est par de tels principes que je rendrai cette ville florissante, et déjà ils m’ont dicté le décret relatif aux enfants d’Œdipe. Qu’Étéocle, qui est mort en combattant pour nos foyers, après avoir signalé sa vaillance, repose dans un tombeau, et qu’on fasse en son honneur les sacrifices dus aux mânes des braves ; mais son frère Polynice , qui n’est revenu de l’exil que pour anéantir dans les flammes sa ville natale et les dieux de son pays, s’abreuver du sang de ses concitoyens, et les emmener en esclavage, je fais proclamer dans la ville la défense de lui donner un tombeau ou de le pleurer, et l’ordre de le laisser sans sépulture, abandonné aux oiseaux de proie et aux chiens dévorants, hideux objet d’épouvante. Telle est ma volonté. Jamais les méchants n’obtiendront de moi les honneurs réservés aux hommes' },
    { k: 'ligne', t: 'vertueux : mais celui qui a bien mérité de la patrie, celui-là, vivant ou mort, sera également honoré par moi.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Telle est ta volonté, Créon, fils de Ménécée, sur l’ennemi de notre patrie, et celui qui fut son ami. Tu as apparemment le droit d’appliquer toute espèce de lois, et à ceux qui sont morts, et à nous qui vivons.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Veillez donc à l’exécution de mes ordres.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Impose ce fardeau à de plus jeunes que nous.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Mais il y a, en effet, des gardes qui veillent auprès du cadavre.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Quel est donc cet autre ordre que tu voudrais nous enjoindre encore ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'De ne pas tolérer ceux qui désobéiraient à mes volontés.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Il n’est pas d’homme assez fou pour désirer de mourir.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tel sera, en effet, le salaire. Mais souvent l’espoir du gain entraîne souvent les hommes à leur perte.' },
    { k: 'perso', t: 'UN GARDE' },
    { k: 'ligne', t: 'O roi, je ne dirai pas que l’empressement m’a mis hors d’haleine, pour avoir couru d’un pied léger. En effet, l’inquiétude m’a fait faire bien des pauses en route, et m’a tenté plusieurs fois de revenir sur mes pas. Je me disais souvent au fond de l’âme : « Où vas-tu, malheureux ? tu cours à ta perte. Mais si tu demeures, Créon apprendra le fait par un autre, et comment alors échapperas-tu au châtiment ? » C’est en roulant de telles pensées dans' },
    { k: 'ligne', t: 'mon esprit, que j’ai été lent à faire la route, et voilà comment un court chemin est devenu long. Enfin, pourtant, la résolution de venir vers toi l’a emporté, et quoique la chose que j’ai à dire soit de peu d’importance, cependant je parlerai ; car je viens guidé par l’espoir qu’il ne m’arrivera rien qui ne soit réglé par la destinée.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Qu’y a-t-il donc qui t’inspire un tel découragement ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Je veux te dire d’abord ce qui m’est personnel ; je n’ai ni fait la chose, ni vu quel était celui qui l’a faite ; et il ne serait pas juste qu’il m’en arrivât malheur.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Vraiment tu prends bien des peines, et tu enveloppes l’affaire de grandes précautions ; il faut que tu aies quelque étrange nouvelle à m’annoncer.' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'C’est qu’en effet les mauvaises nouvelles inspirent beaucoup de crainte.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ne parleras-tu pas enfin , pour t’en aller ensuite, une fois acquitté de ce devoir ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Eh bien ! je vais parler : quelqu’un tout à l’heure a enseveli le mort, et a disparu, après avoir répandu sur le' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Que dis-tu ? quel est l’homme qui a eu cette audace ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Je ne sais ; en effet, le sol n’était ni entamé par la bêche, ni creusé par la pioche ; la terre ferme et âpre n’était ni fendue, ni sillonnée par les roues d’un char, nul indice ne pouvait déceler l’auteur. Dès que le premier garde de jour nous eut révélé le fait, ce fut pour tous une triste surprise ; car le corps, sans être inhumé, n’était plus apparent ; une légère couche, de poussière jetée à la hâte, comme pour éviter le sacrilège, le couvrait. Nulle trace de bête farouche , ni de chien, venu pour le déchirer , n’y apparaissait. Alors éclatèrent les injures réciproques, les gardes s’accusaient mutuellement, et déjà on allait en venir aux coups, et personne n’était là pour calmer la querelle ; chacun semblait être le coupable, mais nul ne pouvait être convaincu de complicité, les preuves manquant. Nous étions tous prêts à manier le fer brûlant, à traverser le feu, à attester les dieux par serment que nous n’étions ni coupables, ni complices de celui qui avait conçu le crime , ou qui l’avait exécuté. Enfin, nos recherches n’aboutissant à rien, l’un de nous ouvrit un avis, qui nous fit tous baisser les yeux de crainte. Car nous ne pouvions ni contredire, ni indiquer rien à faire, qui pût nous tirer d’embarras. Il fallait, disait-il, te faire un fidèle récit, et ne rien cacher. Cet avis prévalut, et c’est moi, infortuné ! que le sort condamna à cette triste commission. C’est à' },
    { k: 'ligne', t: 'regret que je parais devant vous, à qui ma présence déplaît, je le sais ; car personne n’aime à être porteur de mauvaises nouvelles.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'O roi, ce fait ne serait-il pas l’ouvrage des dieux ? Voilà ce que mon esprit se demande depuis longtemps.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Cesse de pareils propos, si tu ne veux mettre le comble à ma colère, et te montrer aussi insensé que tu es vieux ; car tu dis une chose insoutenable, en prétendant que les dieux prennent soin de ce cadavre. Honorent-ils donc comme un bienfaiteur, et eussent-ils enseveli celui qui venait embraser leurs temples entourés de colonnes et leurs offrandes, détruire leur pays et leur culte ? Ou bien vois-tu les dieux protéger les méchants ? Non certes. Mais depuis longtemps des habitants de la ville, mécontents de mes ordres, murmuraient contre moi, secouant la tête en cachette, et ils portaient mon joug de trop mauvaise grâce pour chercher à me complaire. C’est par eux, je le sais parfaitement, que les gardes ont été séduits, à prix d’argent, pour commettre cette infraction aux lois. En effet, il n’est pas pour les mortels d’usage plus funeste que l’usage de l’argent ; c’est lui qui ruine les cités, qui chasse les maris de leurs maisons ; c’est lui qui pervertit les cœurs honnêtes, et leur enseigne le goût des choses honteuses ; il a introduit dans les actions des hommes la fraude et le mépris des lois divines ; il leur enseigne la ruse et l’impiété. Mais ceux que l’appât du gain a entraînés à cette mauvaise action y ont gagné d’en recevoir le châtiment, qui un jour les atteindra. Si donc Jupiter est encore l’objet de ma vénération, sache-le bien, et je te le dis avec serment, si vous ne découvrez l’auteur de cette sépulture interdite, et si vous ne l’amenez devant mes yeux, la mort seule ne suffira pas pour votre châtiment,' },
    { k: 'ligne', t: 'vous serez d’abord pendus tout vifs, si vous ne révélez le coupable, afin de vous apprendre quels sont les gains légitimes, et que désormais, dans vos rapines, vous sachiez qu’il ne faut pas vouloir gagner de toutes les manières. Vous reconnaîtrez alors que les profits déshonnêtes engendrent plus de malheurs que de prospérités.' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Me permettras-tu de dire un mot ? ou dois-je m’en retourner ainsi ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ne sais-tu pas encore à quel point tes discours me fatiguent ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Sont-ce les oreilles ou le cœur qu’ils blessent ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Pourquoi subtiliser ainsi sur l’endroit où tu me blesses ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Le coupable tourmente ton cœur, et moi ton oreille.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ah ! tu es vraiment la loquacité même.' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Au moins ce n’est pas moi qui suis l’auteur du crime.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Et c’est pour de l’argent que tu as livré ta vie.' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Ah ! il est vraiment fâcheux, quand on soupçonne, de' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Fais maintenant de l’esprit sur les soupçons ; mais si vous ne me révélez les coupables, vous pourrez bien dire : Les gains honteux portent malheur.' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Je souhaite de grand cœur qu’on les trouve, mais qu’ils soient découverts ou non, et c’est la fortune qui en décidera, je proteste que tu ne me reverras plus ici. A présent, en effet, sauvé contre toute espérance, je dois aux dieux bien des actions de grâces.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe 1.) Entre toutes les merveilles, il n’est rien de plus merveilleux que l’homme. Il traverse la mer blanchissante sous le souffle orageux du Notos, et affronte les vagues retentissantes ; et la plus grande des divinités, la Terre éternelle, il sillonne son sein inépuisable, retourné chaque année par le soc de la charrue, que traînent des chevaux vigoureux.' },
    { k: 'ligne', t: '[Antistrophe 1.) Par son génie inventif, l’homme attire dans ses pièges l’oiseau à l’esprit léger et la bête farouche, et enveloppe dans ses filets et les peuplades des animaux sauvages, et les habitants des eaux ; il dompte, par d’habiles ruses, les bêtes errantes dans les champs ou sur les montagnes, et il soumet au joug le coursier à l’épaisse crinière et le taureau indompté.' },
    { k: 'ligne', t: '(Strophe 2.) Il s’est approprié la parole et la pensée rapide comme le vent, et s’est formé des mœurs sociables ; il a appris à se garantir sous un toit contre les traits glacés des frimas et contre les torrents de pluie ; son' },
    { k: 'ligne', t: 'génie, fertile en ressources, se précautionne même contre l’avenir ; contre les plus cruelles maladies il a trouvé des remèdes ; contre la mort seule il n’a pas d’asile.' },
    { k: 'ligne', t: '[Antistrophe 2.) Possédant plus qu’il n’osait l’espérer la science et la pratique des arts, il se porte parfois vers le bien, parfois vers le mal ; lorsqu’il associe à ses inventions les lois du pays et la justice divine, vengeresse du parjure, il fait la gloire des cités ; mais il devient indigne d’une patrie, s’il étouffe en lui la vertu par une coupable audace. Puisse-il ne jamais s’asseoir à mon foyer et n’avoir avec moi aucune pensée commune, celui qui agit ainsi !' },
    { k: 'ligne', t: 'Ce prodige divin confond mon esprit ; bien sûr de ce que je vois, comment contester que cette jeune fille soit Antigone ? O malheureuse enfant du malheureux Œdipe, qu’arrive-t-il ? Ce n’est assurément pas pour avoir désobéi aux ordres du roi qu’on t’amène ici, ni pour avoir été surprise dans un acte insensé ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'C’est elle qui a commis le crime ; nous l’avons surprise ensevelissant Polynice. Mais où est Créon ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Le voici fort à propos qui revient du palais.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Eh bien ! qu’y a-t-il ? quel événement rend ma présence nécessaire ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'O roi, les mortels ne peuvent jurer de rien ; en effet, la pensée qui survient dément nos pensées premières.' },
    { k: 'ligne', t: 'Bouleversé tout à l’heure par tes menaces, j’aurais affirmé que je ne me presserais pas de revenir ici. Mais, comme une joie inespérée est sans proportion avec toute autre joie, me voici, malgré mes serments de ne plus revenir, et j’amène cette jeune fille, que l’on a trouvée à préparer la sépulture. Dans cette occasion, l’on a pas tiré au sort ; c’est à moi qu’appartient la trouvaille, et nul autre n’y a droit. Et maintenant, ô roi, reçois toi-même cette jeune fille de mes mains ; interroge-la à ton gré, pour la convaincre. Mais moi, il est juste que je me retire, libre désormais de tout embarras.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Toi qui l’amène, où et comment l’as-tu surprise ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Elle ensevelissait le cadavre ; te voilà instruit de tout.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Comprends-tu et dis-tu bien ce que tu veux dire ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Oui, je l’ai vue inhumer le cadavre que tu avais défendu d’ensevelir : ce langage est-il clair et intelligible ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Comment a-t-elle été vue et prise en faute ?' },
    { k: 'perso', t: 'LE GARDE' },
    { k: 'ligne', t: 'Voici comment la chose s’est passée. À peine arrivés, préoccupés de tes terribles menaces, nous avons balayé toute la poussière qui couvrait le cadavre déjà putréfié, et nous l’avons mis complètement à nu ; puis nous nous assîmes, abrités du vent par des collines élevées, pour éviter d’être atteints par son odeur fétide ; chacun de nous excitant par de vifs reproches l’attention de celui dont la surveillance se relâchait. Cela dura jusqu’au moment où le disque brillant du soleil s’arrêta au milieu du ciel, et fit sentir toute son ardeur. Et alors tout à coup un tourbillon, soulevant de la terre un ouragan,' },
    { k: 'ligne', t: 'fléau des airs, enveloppe la plaine et ravage tous les feuillages des arbres et des plantes ; le vaste éther était rempli de leurs débris, et nous, les yeux fermés, nous supportions le fléau envoyé par les dieux. Lorsque enfin l’ouragan fut dissipé, on voit la jeune fille, poussant des cris aigus, comme un oiseau désolé qui retrouve son nid désert et vide de ses petits ; ainsi, à la vue du cadavre nu, elle aussi laisse éclater ses sanglots, et lance de terribles imprécations contre les auteurs de l’attentat. Aussitôt ses mains le recouvrent de poussière, et, avec un vase d’airain artistement travaille, elle fait de triples libations sur le mort. À cette vue, nous courons à l’instant et la saisissons, sans qu’elle montre aucun trouble. Nous l’interrogeons sur ce qui a précédé, et sur ce que nous avons vu ; elle ne nia rien, et moi, je ressentis tout ensemble de la peine et de la joie ; car il est bien doux d’échapper au châtiment, mais il est pénible d’y livrer ce qui nous est cher. Cependant il est naturel qu’à toutes ces raisons je préfère mon propre salut.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Toi, oui, toi qui tiens les yeux baissés vers la terre, avoues-tu, ou nies-tu avoir fait ce dont il t’accuse ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Oui, j’avoue l’avoir fait, et ne prétends pas le nier.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'didascalie', t: ', au garde.' },
    { k: 'ligne', t: 'Toi, tu peux te retirer à ta volonté, tu es libre de l’accusation qui pesait sur toi. — Pour toi, réponds brièvement et en peu de mots ; connaissais-tu la défense que j’ai fait proclamer ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Je la connaissais ; pouvais-je ne pas la connaître ? elle' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Et pourtant tu as osé enfreindre ces lois ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Ce n’est, en effet, ni Jupiter qui me les a révélées, ni la Justice qui habite avec les divinités infernales, les auteurs de ces lois qui règnent sur les hommes ; et je ne pensais pas que les décrets d’un mortel comme toi eussent assez de force pour prévaloir sur les lois non écrites, œuvre immuable des dieux. Celles-ci ne sont ni d’aujourd’hui ni d’hier ; toujours vivantes, nul ne sait leur origine. Devais-je, les oubliant, par crainte des menaces d’un homme, encourir la vengeance des dieux ? Je savais qu’il me faudrait mourir ; eh ! ne le devais-je pas, même sans ton décret ? Si j’avance l’instant de ma mort, j’y trouve un précieux avantage. Pour quiconque a vécu comme moi dans le malheur, comment ne serait-elle pas un bienfait ? Pour moi donc, ce trépas n’a rien de douloureux ; mais si j’avais laissé sans sépulture le fils de ma mère, c’est alors que je serais malheureuse ; quant à mon sort présent, il ne m’attriste en rien. Pour toi, si ma conduite te paraît insensée, je pourrais dire que c’est un fou qui m’accuse de démence.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'L’esprit inflexible du père se reconnaît dans le caractère inflexible de la fille ; elle ne sait point céder à l’infortune.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Mais, sache-le bien, ces esprits inflexibles s’abattent' },
    { k: 'ligne', t: 'le plus souvent ; et l’on voit souvent le fer le plus dur, endurci encore à l’action du feu, s’user et se briser. Un léger frein réprime la fougue des plus fiers coursiers. Les sentiments d’orgueil ne conviennent pas à qui est esclave des autres. Elle savait qu’elle m’outrageait en violant les lois proclamées ; mais, après avoir commis le crime, elle ajoute pour second outrage d’en tirer vanité, et d’en rire. Certes, je ne serais plus homme, si cette victoire sur mes ordres demeurait impunie. Mais qu’elle soit fille de ma sœur, ou qu’elle soit encore plus rapprochée de moi que par tous les liens du sang, elle et sa sœur n’échapperont point à la mort la plus honteuse ; car j’accuse l’autre autant que celle-ci d’être l’auteur de cette sépulture. Appelez-la ; tout à l’heure je l’ai vue errer dans le palais, égarée, hors d’elle-même, en proie à une démence furieuse, et l’agitation de l’âme trahit d’ordinaire ceux qui machinent dans l’ombre des projets criminels. Mais je déteste le coupable qui essaie de parer sous de belles paroles un crime manifeste.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Je suis ta captive, veux-tu de moi plus que la vie ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Rien de plus ; cela me suffit.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Que tardes-tu donc ? tout comme dans tes discours rien ne me plaît, et ne me plaira jamais, je l’espère , ainsi les miens te sont également désagréables. Cependant quelle gloire plus belle pouvais-je acquérir, que de donner la sépulture à mon frère ? Chacun ici applaudirait à mes paroles, si la crainte ne leur fermait pas la bouche. Mais entre autres heureux privilèges, la tyrannie a encore' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'De tous les Thébains ici présents, tu es la seule à voir de telles choses.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Ils les voient bien aussi, mais leur bouche te flatte !' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Et toi, ne rougis-tu pas de penser autrement qu’eux ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'C’est qu’il n’y a rien de honteux à honorer ceux qui sont nés du même sein que nous.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'N’était-il pas du même sang que toi, celui qui mourut dans le camp opposé ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Oui, du même sang, puis qu’il est né du même père et de la même mère.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Pourquoi donc rendre à Polynice un honneur impie pour son frère, son ennemi ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Il me rendra un autre témoignage, ce mort que je regrette aussi.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Non vraiment, si tu rends des hommages égaux à l’impie.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Il est mort, non pas son esclave, mais son frère.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Mais l’un ravageait sa patrie, l’autre combattait pour elle.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Pluton impose des lois égales pour tous.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Mais l’homme de bien et le méchant ne doivent pas' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Qui sait si aux enfers de telles maximes sont irréprochables ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Certes, jamais un ennemi, même après sa mort, ne devient ami.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'La nature m’a faite pour partager l’amour et non la haine.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Si tu veux aimer, va donc les aimer chez les morts ; mais, de mon vivant, jamais femme ne régnera.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'Mais voici aux portes du palais Ismène, versant des larmes, que fait couler sa tendresse fraternelle ; un nuage sur son front ternit la fraîcheur de son beau visage mouillé de pleurs.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Te voilà donc, toi qui te glissant furtivement dans mon palais, comme une vipère, suçais mon sang ; je nourrissais à mon insu deux fléaux, pour la ruine de mon trône. Eh bien ! dis-moi, avoues-tu aussi avoir pris part à cette sépulture, ou bien protestes-tu de ton ignorance ?' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'J’ai fait ce dont tu m’accuses, si elle me permet de le dire, je partage la faute, et j’en prends ma part.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Mais la justice ne le souffrira pas ; car lu t’y es refusée, et je ne t’ai point associée à mon projet.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Mais dans ton malheur, je ne rougis point de partager tes dangers.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Pluton et les habitants des enfers savent à qui est la' },
    { k: 'ligne', t: 'faute ; pour moi, je ne reconnais point pour amie celle qui n’aime qu’en paroles.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'O ma sœur, ne me prive pas de l’honneur de mourir avec toi, et d’honorer l’ombre d’un frère.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Ne partage pas ma mort, et ne revendique point un acte dont tu n’es pas complice ; ce sera assez que je meure.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Privée de toi, comment la vie pourrait-elle me plaire ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Demande à Créon ; tu prends tant d’intérêt à lui !' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Pourquoi m’affliges-tu sans utilité pour toi ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Ce n’est pas sans douleur que je me ris de toi.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'En quoi donc, maintenant au moins, pourrais-je te servir ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Sauve tes jours ; je te verrai sans jalousie échapper à la mort.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Ah ! malheureuse que je suis ! tu me refuses même de partager ta mort ?' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Nous avons choisi, toi de vivre, moi de mourir.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Mais non sans que je t’en aie dissuadée.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Tes avis étaient bons ; mais j’ai cru le mien plus sage.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Prends courage ; c’est à toi de vivre ; pour moi, depuis longtemps, mon âme est morte, et je ne puis plus être utile qu’aux morts.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'De ces deux filles, je l’affirme, l’une a perdu la raison depuis peu, l’autre depuis qu’elle est née.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'O roi, c’est que la raison, même la plus saine, ne reste point aux malheureux, mais elle les abandonne.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Toi, par exemple, quand tu as choisi le mal, en compagnie des méchants.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Oui, car seule, et sans elle, comment pourrais-je vivre ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Elle ! ne la nomme point ; car elle n’existe plus.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Mais feras-tu périr la fiancée de ton propre fils ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Il trouvera d’autres femmes pour continuer notre famille.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Ce n’était pas là du moins, l’accord réglé entre elle et lui.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Moi, je hais pour mes fils de méchantes épouses.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'O cher Hémon, avec quel mépris te traite ton père !' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Priveras-tu donc ton fils de celle qu’il aime ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'C’est à Pluton qu’il est réservé de rompre ce mariage.' },
    { k: 'perso', t: 'ISMÈNE' },
    { k: 'ligne', t: 'Je le vois, ta résolution est bien prise de la faire périr.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Comme tu le vois, elle est prise. C’est trop de retard, qu’on les emmène, que dès ce moment elles soient traitées en femmes, et privées de liberté. Car les braves mêmes fuient, quand ils voient de près Pluton menacer leur vie.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: '(Strophe 1.) Heureux ceux dont la vie n’a pas senti le malheur ! En effet, ceux dont la colère des dieux ébranle la famille, le sort ne leur épargne aucun malheur et les poursuit dans leur postérité la plus reculée : telle la vague, gonflée par le souffle violent des vents de Thrace, parcourt les ténébreuses profondeurs de la mer, soulève jusqu’au fond de l’abîme le noir limon qu’elle livre aux vents , et les rivages battus des flots répondent par un long mugissement.' },
    { k: 'ligne', t: '(Antistrophe 1.) Je vois les antiques malheurs de la maison des Labdacides s’ajouter aux malheurs des deux princes que la mort a ravis ; une génération frappée n’affranchit pas celle qui la suit, mais un dieu la précipite et ne lui laisse aucun repos. Naguère le jour brillait encore sur le dernier rejeton de la famille d’Œdipe ; cependant le voilà moissonné par la faux sanglante' },
    { k: 'ligne', t: 'des dieux infernaux, par l’égarement de la raison et par la fureur.' },
    { k: 'ligne', t: '(Strophe 2.) O Jupiter ! quel mortel, dans son orgueil, pourrait mettre des bornes à ta puissance, dont jamais ne triomphe ni le sommeil, qui vieillit tout, ni le cours infatigable des ans ? À jamais exempt de vieillesse, tu règnes éternellement au milieu des feux éclatants de l’Olympe. Dans le présent, comme dans le passé et dans l’avenir, voici une maxime salutaire : La foule des mortels ne chemine pas dans la vie sans infortune.' },
    { k: 'ligne', t: '(Antistrophe 2.) En effet, la volage espérance est souvent un appui pour les hommes, et souvent aussi elle est une illusion de frivoles désirs, qui, fallacieuse, se glisse à notre insu, avant que le pied n’ait senti la flamme brûlante. Une parole célèbre de je ne sais quel sage nous dit que le mal prend quelquefois les apparences du bien, aux yeux de celui qu’un dieu pousse à sa perte, et il passe peu d’instants exempts de malheur.' },
    { k: 'ligne', t: 'Mais voici Hémon, le plus jeune de tes enfants ; vient-il, attristé du sort d’Antigone, sa fiancée, déplorer la perte de son hymen ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Nous le saurons bientôt avec plus de certitude que les devins. — Mon fils, instruit de l’arrêt irrévocable rendu contre ta fiancée, viens-tu déployer ta fureur contre ton père, viens-tu lui reprocher le décret rendu contre ton épouse ; ou, quoi que j’aie pu faire, te suis-je toujours cher ?' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Mon père, je suis à toi ; tu me guides par de sages conseils, que je ne refuserai jamais de suivre. Il n’est' },
    { k: 'ligne', t: 'point d’hymen que je puisse justement préférer à tes bonnes directions.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tels doivent être tes sentiments, mon fils ; tout doit céder à la volonté paternelle. En effet, on ne désire avoir et élever dans sa maison des enfants soumis, que pour qu’ils rendent à l’ennemi de leur père mal pour mal, et qu’ils honorent également ses amis. Celui qui engendre des enfants inutiles, que dire de lui, sinon qu’il se prépare des peines à lui-même et de la joie à ses ennemis ? Garde-toi donc, mon fils, de sacrifier ta raison à une femme, et à l’attrait du plaisir ; sache que ce sont de froids embrassements que ceux d’une femme méchante, qui partage notre couche et notre maison. En effet, quelle plaie plus cruelle qu’un perfide ami ? Dédaigne-la donc comme elle le mérite, et laisse-la chercher un époux aux enfers. Puisque, seule entre les Thébains, je l’ai surprise à se révolter ouvertement contre mes ordres, je ne me démentirai point aux yeux des citoyens, elle mourra. Qu’elle implore donc Jupiter protecteur des liens du sang : si je nourris l’esprit de révolte dans mes proches, que devrai-je attendre des étrangers ? Quiconque régit bien sa famille saura aussi gouverner avec justice un État. Mais celui qui transgresse et viole les lois, ou qui veut donner des ordres à ceux qui commandent, celui-là ne saurait obtenir mes éloges. Il faut obéir à celui que l’État a choisi pour maître, en toutes choses, petites ou grandes, justes ou injustes. Un tel homme, j’en ai la confiance, saura également bien commander et bien obéir ; et dans les périls de la guerre, il restera à son poste, et défendra vaillamment ses alliés. L’anarchie est le plus grand des maux ; elle ruine les' },
    { k: 'ligne', t: 'cités, bouleverse les familles, jette les années dans le désordre et la fuite ; ceux, au contraire, qui restent fermes à leur poste, l’obéissance fait leur salut. C’est ainsi qu’on doit venir en aide aux lois établies, et ne jamais céder à une femme. Car il vaut mieux, s’il le faut, succomber devant un homme, et l’on ne nous reprochera pas d’être plus faibles qu’une femme.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Il nous paraît, si notre jugement n’est point affaibli par l’âge, que tes paroles sont dictées par la sagesse.' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Mon père, les dieux donnent aux hommes la raison, le plus précieux de tous les biens. Pour moi, prétendre que tes paroles ne sont pas raisonnables, c’est ce que je n’oserais ni ne saurais jamais dire : cependant un autre aussi peut parler avec sagesse. C’est un devoir naturel pour moi d’être attentif aux actions, aux paroles, aux reproches qui te touchent. Ton regard intimide un simple citoyen, et l’empêche de tenir devant toi des propos qui te déplairaient à entendre ; mais moi, je puis recueillir leurs entretiens secrets ; ils pleurent le sort de cette jeune fille injustement condamnée, entre toutes, au plus cruel supplice, pour l’action la plus belle. « Quoi ! elle n’a point souffert que son frère, tué dans les combats, restât sans sépulture, en proie aux oiseaux et aux chiens dévorants ! Ne méritait-elle pas les plus glorieuses récompenses ? » Tels sont les discours secrets qui viennent jusqu’à nous. Pour moi, mon père, il n’est pas de bien plus précieux que ta prospérité. Y a-t-il en effet un honneur plus désirable pour un fils que la gloire' },
    { k: 'ligne', t: 'd’un père, et pour un père que celle de ses enfants ? Mais ne te persuade pas obstinément que tes avis, à l’exclusion de tout autre, soient les seuls bons et justes. Tel qui croit être seul sage, ou penser et parler mieux que personne, parait souvent dénué de sens à ceux qui l’examinent de près. Mais un homme, un sage même, n’a point à rougir d’apprendre chaque jour, et de ne pas être opiniâtre. Tu vois, auprès des ruisseaux grossis par l’orage, combien d’arbres cèdent au torrent, pour conserver leurs branches ; ceux qui résistent périssent déracinés. De même, le pilote qui tient toujours sa voile tendue, sans rien céder à l’orage, voit bientôt sa barque renversée, et vogue dès lors sur des débris. Modère donc ta colère, et laisse accès à un changement de résolution. Car si, malgré ma jeunesse, j’ai quelque jugement, je dis que ce qu’il y a de mieux pour un homme, c’est d’avoir toute espèce de savoir en partage ; sinon, car d’ordinaire il n’en est pas ainsi, il est encore beau de s’instruire auprès de ceux qui savent.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'O roi, il est juste de l’écouter, s’il ouvre un bon avis, et toi, mon fils, écoute ceux de ton père : car des deux' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Quoi ! à notre âge, nous prendrons des leçons de sagesse d’un si jeune homme !' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'N’en prends que de la justice ; mais si je suis jeune, c’est moins mon âge que mes actes qu’il faut considérer.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'C’est un bel acte, en effet, d’honorer ceux qui violent les lois !' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Non, je ne conseillerais pas d’honorer les méchants.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Mais celle-là n’est-elle pas atteinte de ce mauvais esprit ?' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Tout le peuple de Thèbes le nie.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ainsi Thèbes me dictera les ordres que je dois donner.' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Vois-tu combien tu viens de parler en jeune homme ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Apparemment c’est un autre que moi qui doit régner sur ce pays ?' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'En effet, ce n’est plus une cité, celle qui dépend d’un seul homme.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'La cité n’appartient-elle pas à celui qui gouverne ?' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Il serait beau de régner seul sur une terre déserte !' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'À ce que je vois, il prend le parti de cette femme ?' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Tu es donc femme ? car c’est dans ton intérêt que je' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'O le plus méchant des fils, qui disputes contre ton père !' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Je vois que tu te rends coupable d’une injustice.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'C’est donc me rendre coupable, que de faire respecter mon autorité ?' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Tu ne la fais pas respecter, en foulant aux pieds la majesté des dieux.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'O cœur pervers, subjugué par une femme !' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Tu ne me verras pas du moins céder à une action honteuse.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ainsi toutes tes paroles sont dans l’intérêt de cette femme !' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Et dans le tien, dans le mien, et aussi des dieux infernaux.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Non, jamais tu ne l’épouseras vivante.' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Elle mourra donc, mais elle ne mourra pas seule.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ton audace va-t-elle jusqu’à me menacer ?' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Quelle menace y a-t-il à réfuter des paroles vaines ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tu te repentiras de me donner des leçons, vide de sens comme tu l’es toi-même.' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Esclave d’une femme, ne m’importune pas de ta loquacité.' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Tu veux donc parler seul, et ne veux rien entendre ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Vraiment ! mais par l’Olympe, sache que tu ne m’auras pas impunément outragé. Qu’on amène cet objet de ma haine, pour qu’à l’instant elle expire, en présence et sous les yeux de son fiancé.' },
    { k: 'perso', t: 'HÉMON' },
    { k: 'ligne', t: 'Non, certes, garde-toi de le croire, non, elle ne mourra pas en ma présence ; et toi, jamais tes yeux ne me reverront ; et tu pourras avec tes amis complaisants te livrer à toutes tes fureurs.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'O roi, il s’est retiré, emporté par la colère. À son âge, un tel désespoir est à craindre.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Qu’il parte, qu’il conçoive et exécute des projets plus qu’humains ; quant aux deux jeunes filles, il ne les arrachera pas à la mort.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'Penses-tu donc à les faire périr toutes deux ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Non pas celle qui n’a point touché le cadavre, car ton observation est juste.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'Et par quel supplice songes-tu à faire périr l’autre ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je la mènerai en un désert, dont nul mortel n’approche ; je la cacherai vivante dans une caverne creusée dans le' },
    { k: 'ligne', t: 'roc, elle recevra, comme expiation seulement, tout juste autant de nourriture qu’il en faut pour écarter de la ville toute souillure. Et là, elle pourra peut-être, en invoquant Pluton, le seul dieu qu’elle révère, obtenir de lui qu’il la dérobe à la mort ; ou alors elle sentira, un peu tard peut-être, combien il est superflu d’honorer les dieux infernaux.' },
    { k: 'didascalie', t: '(Créon quitte la scène.)' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: '(Strophe 1.) Amour ! invincible amour ! qui subjugues les puissants de la terre, et reposes sur les joues délicates de la jeune fille ; qui traverses les mers et visites la cabane des bergers, nul parmi les dieux immortels, ni parmi les hommes éphémères, n’échappe à tes traits ; celui que tu possèdes est en proie au délire.' },
    { k: 'ligne', t: '(Antistrophe 1.) Tu pervertis même les cœurs des justes, pour les entraîner à leur perte ; c’est toi qui entre le père et le fils as semé le trouble et la discorde. Puisé dans les regards d’une épouse charmante, le désir triomphe hautement, et prend place parmi les lois suprêmes qui gouvernent le monde. En effet, l’invincible déesse Vénus se joue de nous.' },
    { k: 'ligne', t: 'Et maintenant, moi-même, à ce spectacle, je viole le respect dû aux lois, et je ne puis plus retenir la source de mes larmes, quand je vois Antigone s’avancer vers' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: '(Strophe 2.) Citoyens de Thèbes, ma patrie, vous me voyez faire mon dernier voyage, et regarder pour la dernière fois la brillante lumière du soleil, désormais refusée à mes yeux : Pluton, qui endort tout ce qui respire, m’entraîne vivante aux bords de l’Achéron, sans que j’aie connu l’hymen, dont le chant nuptial ne s’est pas fait entendre pour moi ; mais l’Achéron sera mon époux.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'Aussi, marches-tu glorieuse et admirée vers cette sombre retraite des morts, sans avoir été atteinte par les maladies dévorantes, ni livrée par le sort comme prix du glaive victorieux ; c’est libre et vivante, que, seule entre tous les mortels, tu descendras aux enfers.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: '(Antistrophe 2.) Oui, j’ai entendu raconter que l’étrangère de Phrygie, fille de Tantale, périt de la mort la plus affreuse, sur le mont Sipyle, étouffée par la végétation même du rocher, comme l’arbre sous les étroits replis du lierre ; et si j’en crois les récits des hommes, quoiqu’elle semble se dissoudre, jamais ni les pluies, ni la neige ne l’abandonnent, et les pleurs qui coulent sans cesse de ses yeux arrosent son cou ; ainsi qu’elle, le sort va m’endormir sous une enveloppe de pierre.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'Mais elle était déesse et fille des dieux ; et nous, nous sommes mortels et fils des hommes : cependant il est' },
    { k: 'ligne', t: 'glorieux, en mourant, d’entendre dire que l’on partage la destinée réservée aux dieux.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: '(Strophe 3.) Hélas ! on se rit de moi. Au nom des dieux de ma patrie, pourquoi m’outrager avant ma mort, et tandis que je respire encore ? O ville ! ô citoyens fortunés de cette cité ! sources de Dircé, bois sacrés de Thèbes, glorieuse par ses chars, vous tous, je vous prends tous à témoin que pas un ami ne me donne des larmes, et que les lois, et quelles lois ! m’entraînent vers un rocher, dont on fait un tombeau de forme inouïe, qu’une loi cruelle me contraint de marcher vers une caverne qui doit être mon tombeau ? Hélas ! infortunée ! qui n’habiterai ni avec les humains ni avec les mânes, ni au nombre des morts ni parmi les vivants !' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'Tu as porté ton audace jusqu’à son comble, et, tu as violemment heurté le trône de la Justice, ô ma fille !' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: '{Antistrophe 3.) Ah ! tu as touché ma plus cuisante blessure, les infortunes accumulées de mon père, et de toute notre race fatale des glorieux Labdacides. O crime du lit maternel ! O incestueux embrassements de ma triste mère avec mon père, qu’elle-même avait enfanté, à qui je dois la vie, et vers lesquels je vais, infortunée, chargée d’imprécations, privée d’hymen, pour partager leur demeure ! O mon frère, c’est ton funeste hymen, c’est ta mort qui m’arrache la vie.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'La piété envers les morts est respectable ; mais l’autorité, pour celui qui la garde est tout à fait inviolable : toi, c’est ton caractère volontaire, indépendant, qui t’a perdue.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: '(Épode.) Sans consolations, sans amis, sans époux, je suis entraînée sur cette route qui m’attend. Malheureuse, il ne me sera plus permis de voir la sainte clarté du soleil, et nul ami ne donne à mon sort ni larmes ni regrets.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Savez-vous bien que s’il fallait tant de lamentations et de gémissements avant de mourir, personne n’en finirait ? Que tardez-vous à l\'emmener ? Renfermez-la, et abandonnez-la seule et solitaire, dans ce tombeau obscur, comme je l’ai prescrit, soit qu’elle désire y mourir, ou être ensevelie vivante dans une telle demeure : ainsi nous serons purs de la mort de cette jeune fille, et elle restera privée du commerce des vivants.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'O tombeau ! ô chambre nuptiale ! ô demeure creusée dans le roc, ma prison éternelle, où je vais retrouver aux enfers mes proches, dont Proserpine a déjà reçu le' },
    { k: 'ligne', t: 'plus grand nombre parmi les morts ; je descends la dernière et la plus misérable, avant que le terme marqué à ma vie par le destin soit achevé. Là, du moins, je nourris, dans mon cœur l’espérance d’être reçue en amie par un père, par toi, ma mère, par toi, frère chéri : car j’ai lavé de mes propres mains vos corps inanimés, je les ai parés, et j’ai versé sur votre tombe les libations funèbres ; et maintenant, cher Polynice, c’est pour avoir enseveli ton corps que je reçois cette triste récompense. Cependant je t’ai justement honoré, au jugement des sages. Jamais pour des enfants, si j’eusse été mère, jamais pour un époux, si j’avais eu à pleurer sa mort, je n’aurais tenté une pareille tâche malgré les défenses publiques. Quel est donc le motif qui m’inspire ce langage ? Après la perte d’un époux, j’en pourrais trouver un autre ; et si je perdais un fils, j’en puis avoir d’un autre époux ; mais quand ma mère et mon père sont descendus chez Pluton, la perte d’un frère n’est plus réparable. C’est pour avoir rempli envers toi ce devoir sacré, que Créon m’a jugée coupable, et qu’il m’accuse d’attentat, ô frère chéri ! Et maintenant il m’a saisie, ses mains m’entraînent, vierge encore, avant que j’aie connu les joies de l’hymen et les plaisirs de la maternité. Mais ainsi abandonnée de mes amis, malheureuse, je descends vivante au sombre séjour des morts. Quelle loi divine ai-je donc violée ? À quoi bon tourner encore vers les dieux mes regards suppliants ? Quel défenseur appeler, puisque ma piété même m’attire les' },
    { k: 'ligne', t: 'peines réservées aux impies ? Eh bien ! si le sort qu’on me fait est approuvé des dieux, je reconnais que je souffre par ma faute ; mais si le tort est à mes persécuteurs, je ne leur souhaite pas plus de maux que ne m’en cause leur injustice !' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'Les mêmes orages des mêmes passions agitent encore son âme.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Aussi, ferai-je repentir de ces lenteurs ceux qui tardent à l’emmener.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'Hélas ! cette parole m’annonce ma mort prochaine.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ne te flatte pas que rien puisse arrêter l’accomplissement de mes ordres.' },
    { k: 'perso', t: 'ANTIGONE' },
    { k: 'ligne', t: 'O ville de Thèbes, ma patrie ! dieux de ma famille ! c’en est donc fait, on m’entraîne. Chefs thébains, voyez la seule fille qui reste de vos rois, voyez à quel supplice et par quels juges je suis condamnée, pour être restée fidèle au culte de la piété.' },
    { k: 'didascalie', t: '(On emmène Antigone.)' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: '(Strophe 1.) Danaé aussi eut la douleur d’échanger la lumière céleste pour les ténèbres d’une prison d’airain ; cachée à tous les yeux, elle resta enchaînée dans ce triste tombeau ; et cependant, ô ma fille, ma fille, sa naissance était illustre, et elle recéla dans son sein la pluie d’or de Jupiter. Mais le Destin est une puissance redoutable ; ni' },
    { k: 'ligne', t: 'la tempête, ni Mars, ni les tours, ni les noirs vaisseaux battus par les vagues ne peuvent lui échapper.' },
    { k: 'ligne', t: '(Antistrophe 1.) L’irascible fils de Dryas , roi des Édones, fut enchaîné et enfermé au fond d’un rocher pour prison, par l’ordre de Bacchus, pour ses violents outrages. Ainsi s’apaisa par degrés cette fureur terrible. Il reconnut le dieu que, dans sa folie, il avait blessé par d’outrageantes paroles. Il avait voulu faire cesser les orgies des Bacchantes, et éteindre les torches de Bacchus, et il avait irrité les Muses, qui se plaisent aux doux sons des flûtes.' },
    { k: 'ligne', t: '(Strophe.) Près des ondes Cyanées, et de la double mer sont les rivages du Bosphore et Salmydesse, ville des Thraces, où le dieu Mars, qu’on y adore, a vu l’horrible blessure faite aux deux fils de Phinée, privés de la lumière (attentat qui criait vengeance), par une cruelle marâtre, qui, sans glaive, armant ses mains sanglantes d’une navette aiguë, en enfonça la pointe dans le globe de leurs yeux.' },
    { k: 'ligne', t: '(Antistrophe 2.) Consumés par la douleur, ces' },
    { k: 'ligne', t: 'malheureux pleuraient les malheurs de leur mère, dont l’hymen leur avait donné une naissance si funeste ; elle descendait des antiques Érechtides ; fille de Borée, nourrie en des antres écartés et au sein des orages paternels, elle devançait les coursiers sur la glace affermie ; dans ses veines coulait le sang des dieux, et cependant, ô ma fille, les Parques immortelles ne l’ont point épargnée.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Chefs de Thèbes, nous avons fait route ensemble, deux à deux, éclairés par les yeux d’un seul ; car les aveugles ne peuvent marcher sans guide.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Qu’y a-t-il de nouveau, vieux Tirésias ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Je te l’apprendrai ; et toi, crois aux paroles du devin.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Jusqu’ici du moins, je ne me suis point écarté de tes avis.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'C’est pour cela que tu as bien dirigé le gouvernail de l’État.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je puis témoigner qu’ils m’ont été utiles.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Songe que tu es encore maintenant dans une conjoncture critique.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Qu’y a-t-il ? tes paroles me font frissonner.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Tu le sauras ; écoute ce que va révéler mon art. J’étais' },
    { k: 'ligne', t: 'assis sur le trône augural, dans un lieu que des oiseaux de toute espèce ont choisi pour retraite, lorsque j’entendis des sons inconnus d’oiseaux en fureur, poussant des cris barbares ; ils se déchiraient les uns les autres avec leurs serres ensanglantées ; c’est ce que je reconnus au bruit de leurs ailes. Effrayé, je me hâtai d’interroger la flamme allumée sur l’autel ; mais elle ne brillait pas sur le corps des victimes ; les parties des chairs mises en ébullition s’exhalaient en fumée, ou se consumaient en cendres ; le fiel éclatait dans les airs, et les cuisses tombaient dépouillées de la graisse dont on les avait enveloppées. Tels étaient les funestes présages du sacrifice, que j’apprenais de cet enfant, car il est mon guide comme je suis le guide des autres ; et ce fléau, c’est ta funeste résolution qui l’attire sur Thèbes. En effet, tous nos autels et nos foyers sacrés sont souillés des lambeaux arrachés par les oiseaux et les chiens dévorants au cadavre de l’infortuné fils d’Œdipe. Aussi, les dieux n’accueillent plus nos prières mêlées aux sacrifices, ni la flamme des victimes, et les oiseaux ne font plus entendre de chants favorables, depuis qu’ils se sont repus de la chair et du sang d’un homme égorgé. Songes-y donc, mon fils, c’est le partage de tous les hommes de faire des fautes ; mais la faute une fois faite, celui-là n’est plus insensé ni malheureux, qui après être tombé dans le mal, y applique le remède, au lieu de rester dans l’inaction. C’est la présomption opiniâtre qui encourt le reproche d’ignorance. Mais cède à la mort, et ne frappe pas un cadavre. Quelle vaillance y a-t-il à tuer un mort ? C’est par intérêt pour toi que je te donne ce sage avis ; il est' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Vieillard, je suis un but contre lequel, tous, comme autant d’archers, vous lancez vos traits, je ne suis pas même à l’abri de vous autres devins, depuis longtemps je suis vendu par votre race, et le jouet de votre vénalité. Livrez-vous à ces trafics, amassez, si vous voulez, tout l’or de Sardes ou de l’Inde ; vous ne donnerez jamais à cet homme les honneurs de la sépulture ; quand même les aigles voraces de Jupiter voudraient porter jusque sur son trône des lambeaux de ce cadavre, non jamais, par crainte de cette souillure, je ne permettrai de l’ensevelir. Car je sais bien que nul mortel ne peut souiller les dieux. O vieux Tirésias, les hommes les plus habiles font souvent une chute honteuse, lorsque l’appât du gain leur fait parer d’un beau langage de honteuses pensées.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Hélas ! quel est le mortel qui sache, qui comprenne...' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Quoi ? quel est ce lieu-commun que tu vas nous débiter ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: '. . . combien la prudence est le plus précieux des trésors.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Autant, je crois, que l’imprudence est le plus grand des maux.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Tel est pourtant le mal dont tu es atteint.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je ne veux point répondre à un devin par des injures.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'C’est pourtant ce que tu fais, en traitant mes prophéties' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'C’est que toute la race des devins aime l’argent.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Et la race des tyrans aime les gains honteux.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Sais-tu bien que tes discours s’adressent au maître de ce pays ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Je le sais ; car c’est à moi que tu dois d’en être le sauveur et le maître.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tu es un habile devin, mais tu aimes à faire le mal.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Tu me forceras à révéler les secrets que je gardais au fond de mon cœur.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Révèle tout ; seulement, que l’intérêt ne te fasse point parler.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'En effet, je commence à le croire aussi, l’intérêt me fait parler, mais c’est le tien.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Sache que tu ne trafiqueras pas de ma volonté.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Et toi, sache bien qu’avant que le char rapide du soleil n’ait achevé plusieurs tours de ses roues, par la mort d’un enfant né de ton sang, tu payeras à ton tour les morts par toi sacrifiés, pour te punir d’avoir ignominieusement enfermé dans un tombeau une âme vivante, et aussi de retenir sur la terre, privé de sépulture et des honneurs funèbres, un cadavre qui appartient aux dieux infernaux. Car ni toi ni les dieux du ciel n’avez aucun' },
    { k: 'ligne', t: 'droit sur lui ; mais c’est toi qui leur fais violence. Aussi, déjà les Furies vengeresses des dieux de l’enfer et du ciel, qui marchent à la suite des criminels pour les frapper, t’épient, pour te précipiter dans les mêmes malheurs. Considère maintenant si c’est l’argent qui dicte mes paroles. Encore quelques instants, et les lamentations des hommes et des femmes retentiront dans ton palais. Déjà s’arment indignées les villes des guerriers dont les chiens, les loups et les vautours ont déchiré les cadavres, et souillé d’exhalaisons fétides les autels consacrés. Car tu m’as irrité ; tels sont les traits que mon ressentiment, comme un archer, a lancés contre toi, et dont tu n’éviteras pas les cuisantes blessures. Enfant, reconduis-moi dans ma demeure, laissons-le exhaler sa colère contre de plus jeunes, et qu’il apprenne à modérer sa langue, et à nourrir des sentiments meilleurs que ceux qui l’animent.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'O roi ! il est parti, en nous laissant des prédictions terribles ; or, je sais, depuis que l’âge a ainsi blanchi mes cheveux, qu’il n’a jamais annoncé à Thèbes d’oracles mensongers.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je le sais comme toi, et mon cœur en est troublé. En effet, céder est dangereux, mais il n’y a pas moins de danger à s’attirer quelque désastre par la résistance et la colère.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Que faut-il donc faire ? Parle ; j’obéirai.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Va délivrer la jeune fille de sa prison souterraine, et érige un tombeau au cadavre gisant.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ce sont là les conseils que tu me donnes, et auxquels je dois me rendre ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Oui, et le plus promptement possible ; car la vengeance des dieux est prompte à atteindre les mortels téméraires.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Hélas ! ce n’est pas sans peine que je renonce à mon projet ; mais il ne faut pas lutter tellement contre la nécessité.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Va donc, et agis , sans te reposer de ce soin sur un autre.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'J’y vais de ce pas. Allez, allez, vous tous, serviteurs, présents et absents, prenez en main des haches, et courez sur cette colline. Pour moi, puisque j’ai ainsi changé de dessein, je la délivrerai moi-même, de la même main qui l’avait enchaînée. Car, je le crains, le parti le plus sage est de vivre en observant les lois établies.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe 1.) Toi qu’on adore sous tant de noms divers,' },
    { k: 'ligne', t: 'et qui fais les délices de la fille de Cadmus, rejeton de Jupiter qui fait gronder la foudre, protecteur de la glorieuse Italie, et de la contrée où les fêtes de Cérès Éleusinienne attirent un si grand concours, Bacchus, qui te plais au séjour de Thèbes, nourrice des Bacchantes, sur les bords arrosés par l’Isménos, aux lieux où furent semées les dents du farouche dragon :' },
    { k: 'ligne', t: '(Antistrophe 1.) Une flamme brillante luit en ton honneur sur la double colline fréquentée par les nymphes Coryciennes, suivantes de Bacchus, et baignée par les eaux de Castalie ; du mont Nysa couvert de lierre, et de ses côteaux chargés de vignes verdoyantes, tu viens, au bruit des chants sacrés des Bacchantes, visiter les places publiques de Thèbes ;' },
    { k: 'ligne', t: '(Strophe 2.) Thèbes, honorée entre toutes les villes, par toi et par ta mère, victime de la foudre, aujourd’hui encore, que la ville entière est en proie à un cruel fléau, viens la sauver par ta présence, en franchissant les hauteurs du Parnasse ou le détroit retentissant.' },
    { k: 'ligne', t: '(Antistrophe 2.) O toi, qui conduis le chœur des astres étincelants, et qui présides aux chants nocturnes, jeune fils de Jupiter, viens, escorté des Thyades de Naxos, tes compagnes, qui, pendant toute la durée des nuits, forment des danses en l’honneur de leur maître Iacchos.' },
    { k: 'perso', t: 'UN ENVOYÉ' },
    { k: 'ligne', t: 'Habitants de la cité de Cadmus et d’Amphion, il n’est pas d’homme, quelle que soit sa condition, dont je puisse désormais ni vanter le bonheur, ni blâmer la misère. En effet, c’est toujours la fortune qui élève, c’est la fortune qui abat tour à tour l’homme heureux et le malheureux, et nul devin ne peut prédire aux mortels une destinée durable. Créon naguère me paraissait digne d’envie, il avait délivré de ses ennemis la terre de Cadmus, et la gouvernait avec un empire absolu, il était père d’une noble et florissante famille ; et maintenant tout ce bonheur s’est évanoui. Car celui qui perd à jamais le plaisir ne vit plus, à mon sens, ce n’est plus qu’un cadavre animé. Entasse, si tu le veux, d’immenses richesses dans ton palais, que ta vie étale un faste royal ; tous ces biens, si la joie ne les accompagne, je ne les achèterais pas, en' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Quel nouveau malheur de nos rois viens-tu nous annoncer ?' },
    { k: 'perso', t: 'L’ENVOYÉ' },
    { k: 'ligne', t: 'Ils sont morts ; et ceux qui leur survivent sont la cause de leur trépas.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Lequel est le meurtrier ? quel est le ravisseur ? parle.' },
    { k: 'perso', t: 'L’ENVOYÉ' },
    { k: 'ligne', t: 'Hémon a péri ; une main amie a versé son sang.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Est-ce de la main de son père, ou de la sienne propre ?' },
    { k: 'perso', t: 'L’ENVOYÉ' },
    { k: 'ligne', t: 'Il s’est frappé lui-même, irrité contre son père, pour le meurtre d’Antigone.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'O Tirésias ! comme l’événement a confirmé ta prédiction !' },
    { k: 'perso', t: 'L’ENVOYÉ' },
    { k: 'ligne', t: 'Dans cet état de choses, il est à propos de songer aux suites.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Mais j’aperçois près de nous la triste Eurydice, l’épouse de Créon ; elle sort du palais, soit qu’elle ait entendu parler du malheur de son fils, soit amenée par le hasard.' },
    { k: 'perso', t: 'EURYDICE' },
    { k: 'ligne', t: 'Thébains ici assemblés, j’ai entendu vos paroles, au moment où j’allais sortir pour adresser mes prières à la divine Pallas. J’ouvrais les portes, après avoir tiré les verroux, lorsque je ne sais quel mot de malheur' },
    { k: 'ligne', t: 'domestique a frappé mes oreilles. Dans mon effroi, je tombai renversée entre les bras de mes femmes, et je perdis l’usage de mes sens. Mais quel était ce récit ? répétez-le moi, j’ai l’expérience du malheur, et je vous écouterai.' },
    { k: 'perso', t: 'L’ENVOYÉ' },
    { k: 'ligne', t: 'Chère maîtresse, je parlerai en témoin oculaire, et je n’omettrai pas un mot de la vérité ; pourquoi emploierais-je avec toi des ménagements, qui ensuite seraient convaincus de mensonges ? la vérité est toujours dans le droit chemin. J’accompagnais ton époux, et le menais sur le plateau élevé où gisait encore le cadavre de Polynice, impitoyablement déchiré par les chiens. Là, après avoir supplié Hécate et Pluton de calmer leur colère, et fait les saintes ablutions, nous avons brûlé les restes du corps sur un amas de branches fraîchement coupées, puis, après avoir édifié en forme de tombeau des monceaux de terre natale, nous nous dirigions vers la caverne dont Pluton avait dû faire le lit nuptial de la jeune fille. Mais de loin, un de nous entend des gémissements aigus partir de cet asile de l’hymen et de la mort, et il accourt l’annoncer à notre maitre Créon. Celui-ci entend, à mesure qu’il approche, des cris inarticulés et déchirants, il soupire, et laisse échapper ces mots lamentables : « Malheureux ! mes pressentiments doivent-ils se vérifier ? suis-je donc ici sur la plus funeste des routes que j’aie parcourues ? La voix de mon fils trouble mon âme. Serviteurs, accourez, hâtez-vous, approchez du tombeau, arrachez la pierre qui obstrue l’entrée, pénétrez dans l’ouverture même, et vérifiez si c’est bien la voix d’Hémon que j’ai entendue, ou si les dieux m’abusent. »' },
    { k: 'ligne', t: 'Pour obéir aux ordres de notre maître désespéré, nous regardons, et au fond de la tombe, nous voyons Antigone suspendue par le cou, attachée à un lacet formé avec sa ceinture de lin ; et près d’elle, Hémon étendu, la serrant dans ses bras, pleurant la mort de l’épouse que l’enfer lui a ravie, la cruauté de son père et son funèbre hyménée. Créon, dès qu’il le voit, gémit amèrement, pénètre jusqu’à lui, et s’écrie avec des sanglots : « O malheureux, quel acte as-tu accompli ? quelle était ta pensée ? de quel coup fatal t’es-tu frappé ? sors, mon fils, je t’en supplie ! » Mais le fils, lui jetant un regard farouche, dédaigne ses prières, et, sans répondre, tire une épée à double tranchant ; son père fuit et échappe au coup ; alors, tournant son courroux contre lui-même, le malheureux Hémon se jette au même instant sur la pointe de son épée, il s’en perce le sein, et respirant encore, il s’enlace entre les bras défaillants de la jeune fille, et exhale sur son pâle visage le dernier soupir avec des flots de sang. Les deux corps gisent mutuellement embrassés, et leur hymen s’accomplit dans le triste séjour de Pluton ; exemple qui montre aux hommes combien l’imprudence entraine de désastres.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'perso', t: 'L’ENVOYÉ' },
    { k: 'ligne', t: 'Cette retraite subite m’étonne aussi ; j’espère toutefois que, désespérée de la mort de son fils, et ne voulant pas donner aux citoyens le spectacle de sa douleur, elle est rentrée dans le palais, pour y déplorer avec ses femmes le massacre de sa famille. Car elle n’est pas assez dépourvue de sens pour faire une chose indigne d’elle.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Je ne sais ; pour moi, du moins, et le morne silence, et les grands cris du désespoir me paraissent annoncer quelque chose de sinistre.' },
    { k: 'perso', t: 'L’ENVOYÉ' },
    { k: 'ligne', t: 'Eh bien ! nous saurons, en entrant dans le palais, si, au fond de son cœur ulcéré, elle ne cache pas une douleur qu’elle comprime ; car, tu dis vrai, ce morne silence annonce quelque chose de sinistre.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Mais voici le roi lui-même qui s’avance, portant dans ses bras le gage de son deuil, expiant, si j’ose le dire, sa propre faute et non celle d’un autre.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: '(Strophe 1.) O cruel et mortel égarement d’un cœur dénaturé ! voyez le meurtrier et la victime, qu’unissaient les liens du sang ! Hélas ! funestes effets de ma vengeance ! O mon fils ! mon fils ! mon fils ! enlevé si jeune par une mort prématurée ! hélas ! tu meurs, tu péris par mes fautes et non par les tiennes.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Hélas ! c’est bien tard que tu reconnais la justice des dieux.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: '(Strophe 2.) Hélas ! je le reconnais que trop ; alors,' },
    { k: 'ligne', t: 'oui, alors, un dieu courroucé contre moi est venu fondre sur ma tête, et m’a poussé dans des voies cruelles. Hélas ! il a d’un pied impitoyable renversé mon bonheur. Hélas ! hélas ! ô vains labeurs des mortels !' },
    { k: 'perso', t: 'UN SECOND MESSAGER' },
    { k: 'ligne', t: 'O mon maître ! dans l’état où tu es, et sous les maux qui t’accablent, tu as les uns sous les yeux, et les autres t’attendent dans le palais, et tu vas bientôt les voir.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'À quel malheur pire que ceux-ci dois-je m’attendre encore ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Ton épouse est morte, en montrant sa tendresse pour ce fils qui n’est plus, par le coup fatal dont elle vient de se frapper.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: '(Antistrophe 1.) O séjour inexorable de Pluton, pourquoi donc, pourquoi t’acharnes-tu à ma perte ? O triste messager de douleur, que m’annonces-tu ? Hélas ! hélas ! tu me donnes une seconde fois la mort ! Parle, que viens-tu m’apprendre de nouveau ? Ainsi, à la perte désastreuse de mon fils, faut-il ajouter la mort sanglante de mon épouse ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Tu peux la voir ; car elle n’est plus dans l’intérieur du palais.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Hélas ! je vois ici mon second malheur. Quel sort donc, quel sort m’est encore réservé ? j’ai entre mes bras le corps de mon fils qui vient d’expirer, et sous mes yeux' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Frappée d’une profonde blessure, elle embrasse l’autel, et ferme ses yeux mourants , après avoir déploré la glorieuse mort de Mégarée et celle de son second fils ; enfin elle a lancé des imprécations terribles contre toi, meurtrier de ses enfants.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: '{Strophe 2.) Hélas ! la frayeur me bouleverse. Que tarde-t-on à me percer le sein d’un glaive à deux tranchants ? Ah ! malheureux ! je suis en proie à un sort fatal.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Elle t’accusait en mourant d’être l’auteur de la mort de ses deux fils.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Et de quelle manière est-elle morte ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'En se frappant elle-même au cœur, de sa propre main, dès qu’elle apprit le sort lamentable de son fils.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: '(Strophe 3.) Hélas ! je n’en puis accuser nul autre que moi-même. C’est moi, en effet, c’est moi qui t’ai donné la mort, je l’avoue. O mes amis, retirez-moi, enlevez-moi de ces lieux, moi qui ne compte plus parmi les vivants.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'C’est là un avantage, s’il en est dans le malheur, car entre les maux présents, les plus courts sont les meilleurs.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: '(Antistrophe 2.) Qu’elle vienne, qu’elle apparaisse, cette destinée dernière, amenant le plus beau de mes jours, celui qui sera le terme de ma vie ! Qu’elle vienne,' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Ceci est de l’avenir ; laissons-en le soin à ceux qu’il regarde ; c’est du présent qu’il faut nous occuper.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Puissé-je les voir s’accomplir, ces vœux que j’ai formés !' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Ne forme point de vœu ; car il n’est point donné aux mortels d’échapper à leur destinée.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: '(Antistrophe 3.) Emmenez donc un infortuné qui, sans le vouloir, t’a tué, ô mon fils, et toi aussi, chère épouse ! O malheureux ! je ne sais où tourner les yeux, ou courir ; car tout le présent est perdu pour moi, et quant à l’avenir, un destin insupportable l’a suspendu sur ma tête.' },
    { k: 'perso', t: 'LE CHOEUR' },
    { k: 'ligne', t: 'La sagesse est de beaucoup le gage le plus certain du bonheur ; il ne faut jamais oublier ses devoirs envers les dieux ; les paroles présomptueuses attirent des châtiments sévères sur les orgueilleux, et leur enseigne une tardive prudence.' },
  ],
};

export default texte;
